OnOpenPage()

{

	// Add your component and variables initialization code here

	// WARNING: All variables definied on this function are global for this page

//   if(IsProject()==0)   int textMode=0;

   int textMode=0;



   int step=0;

   int curRyb=0;

   int ready=1;

   int view=0;

   int curPlay=0;

   int niesp=0;

   int przyciskPhase;

   int noMove=0;

   int curView=0;

   int curmusic=3;



   int przedmioty[4];



   LoadGroup("cursors.grp");

   SetCursor(0);



//#############################################################################

   int toolbar=0;

   int toolbarCase=0;

   int toolbarPhase=0;

   int txtHotSpotOn=0;

   int playStatus=0;

   int puzzleNo=0;

   Group.HotSpot_Holder.DisableHotSpot(1);

//############################################################################



   HotSpot_Holder.DisableHotSpot(8);

   Sound_Holder.PlayDSound(curmusic);

   SetTextMode();

   FadeScreen(1,1000);

//   SetTimer(5000);

}





void SetTextMode(void)

{

   if(textMode)

   {

      curPlay=0;

      niesp=0;

      przyciskPhase=0;

      noMove=0;

      przedmioty[0]=0;

      przedmioty[1]=0;

      przedmioty[2]=0;

      HotSpot_Holder.DisableHotSpot(8);

      HotSpot_Holder.EnableHotSpot(5);

      HotSpot_Holder.EnableHotSpot(6);

      HotSpot_Holder.EnableHotSpot(7);



      DisableScreen();

      Sprite_Holder.HideSprite(3);

      MultiBitmap.HideBitmap(curView+10);

      MultiBitmap.HideBitmap(curView);

      Sound_Holder.Stop(curmusic);

      Sprite_Holder.ChangePhase(4,przyciskPhase);

      Sprite_Holder.HideSprite(3);

      Sprite_Holder.HideSprite(4);

      EnableScreen();

      ShowBuffer();

      curmusic=3;

      curView=0;

      Sound_Holder.PlayDSound(curmusic);



      playStatus = 1;

      Sound_Holder.SetPlayDSoundParameters(curmusic,-1000,0,0);

      Sound_Holder.PlayDSound(0);

      Text_Holder.SetTextOffsets(0,0,0);

      Text_Holder.DisableMouse(0);

      Text_Holder.ShowText(0);

      if(ready==0)

         Sprite_Holder.StopAnimation(0);

      Transparent_Video_Holder.Stop();

   }

   else

   {

      Sound_Holder.SetPlayDSoundParameters(curmusic,0,0,0);

      playStatus = 0;

      Text_Holder.HideText(0);

      Text_Holder.StopSynchroText(0);

      if(ready==0)

         Sprite_Holder.ContinueAnimation(0);

      curPlay=0;

      Transparent_Video_Holder.Play(0,0);

   }

}



void OnClosePage(void)

{

	// Add your close page handler code here



}







void HotSpot_Holder.MouseMoveIn(int rectID)

{

   if(curPlay || textMode || (noMove && rectID!=8))   return;

   switch(rectID)

   {

      case 0:

         if(noMove)   return;

         ready=0;

         view=1;

         Sprite_Holder.GotoXY(0,-640,0);

         SetCursor(7);

         break;

      case 1:

         if(noMove)   return;

         ready=0;

         view=0;

         Sprite_Holder.HideSprite(3);

         Sprite_Holder.GotoXY(0,0,0);

         SetCursor(6);

         break;

      case 3:

      case 4:

      case 5:

         if(view==0 && ready)  SetCursor(1);

         break;

      case 6:

      case 7:

         if(view==1 && ready)  SetCursor(1);

         break;

      case 8:

         SetCursor(1);

         break;

   }

}





void Transparent_Video_Holder.TheEnd(int videoID)

{

   if(textMode || noMove)   return;

   if(videoID>2)

   {

      Transparent_Video_Holder.HideFirsLastVideoFrame(videoID);

      curPlay=0;

      if(niesp && view)  

      {

         Sprite_Holder.ShowSprite(3);

         HotSpot_Holder.EnableHotSpot(8);

      }

   }

   curRyb++;

   if(curRyb>2)   curRyb=0;

   Transparent_Video_Holder.Play(curRyb,0);

}





void Sprite_Holder.InPlace(int spriteID,int x,int y)

{

   ready=1;

   SetCursor(0);

   if(niesp && x==-640)

   {

      Sprite_Holder.ShowSprite(3);

      HotSpot_Holder.EnableHotSpot(8);

   }

}





void HotSpot_Holder.LeftButtonClickOn(int rectID)

{

   if(ready==0 || textMode || (noMove && rectID!=8))   return;

   switch(rectID)

   {

      case 3:

      case 4:

         if(view==0)

         {

            curPlay=rectID;

            Transparent_Video_Holder.Play(rectID,0);

         }

         break;

      case 5:

      case 6:

      case 7:

         rectID-=5;

         if(((view==0 && rectID==0) || (view && rectID)) && przedmioty[rectID]==0)

         {

            curPlay=rectID+5;

            Transparent_Video_Holder.Play(curPlay,0);

            przedmioty[rectID]=1;

            HotSpot_Holder.DisableHotSpot(curPlay);

            SetCursor(0);

            int xx=0;

            while(xx<3)

            {

               if(przedmioty[xx]==0)   break;

               xx++;

            }

            if(xx==3)   niesp=1;

         }

         break;

      case 8:

         if(przyciskPhase==0)

         {

            noMove=1;

            Sprite_Holder.ShowSprite(4);

            Sound_Holder.PlayDSound(1);

         }

         else

         {

            if(przyciskPhase<13)

            {

               Sound_Holder.PlayDSound(1);

               Sprite_Holder.ChangePhase(4,przyciskPhase);

            }

            else

            {

               Transparent_Video_Holder.Stop();

               MultiBitmap.ShowBitmap(curView+10,363,416,4);

               Sprite_Holder.HideSprite(3);

               Sound_Holder.PlayDSound(2);

               MultiBitmap.HideBitmap(curView+10);

               curView++;

               if(curView>9)   curView=0;

               Sound_Holder.Stop(curmusic);

               curmusic=curView+3;

               MultiBitmap.ShowBitmap(curView,0,0,3);

               if(curView)

                  MultiBitmap.HideBitmap(curView-1);

               else

                  MultiBitmap.HideBitmap(9);

               Sound_Holder.PlayDSound(curmusic);

            }   

         }

         przyciskPhase++;

         break;

   }

}





void HotSpot_Holder.MouseMoveOut(int rectID)

{

   SetCursor(0);

}



//############################################################# T O O L B A R #######

//#############################################################---------------#######

void Group.HotSpot_Holder.MouseMoveIn(int rectID)

{

   switch(rectID)

   {

      case 0:

         Group.HotSpot_Holder.DisableHotSpot(0);

         if(ready==0 && textMode==0)  Sprite_Holder.StopAnimation(0);

         Group.Sprite_Holder.DisableTimers();



         Group.Sprite_Holder.GotoXY(0,480,0);

         Group.Sprite_Holder.GotoXY(2,544,14);

         Group.Sprite_Holder.GotoXY(3,584,14);

         Group.Sprite_Holder.GotoXY(4,515,84);

         Group.Sprite_Holder.GotoXY(5,559,210);

         Group.Sprite_Holder.GotoXY(6,558,282);

         Group.Sprite_Holder.GotoXY(7,557,404);



         Group.Sprite_Holder.SynchronizeTimers();

         Group.Sprite_Holder.EnableTimers();

         Group.Sound_Holder.PlayDSound(0);

         break;

      case 1:

         if(toolbar)

         {

            Group.Sprite_Holder.DisableTimers();

            Sprite_Holder.DisableTimers();

            Group.Sprite_Holder.GotoXY(0,640,0);

            Group.Sprite_Holder.GotoXY(7,717,404);



            switch(toolbarPhase)

            {

               case 0:

                  Group.Sprite_Holder.GotoXY(2,704,14);

                  Group.Sprite_Holder.GotoXY(3,744,14);

                  Group.Sprite_Holder.GotoXY(4,675,84);

                  Group.Sprite_Holder.GotoXY(5,719,210);

                  Group.Sprite_Holder.GotoXY(6,718,282);

                  break;

               case 1:

                  Sprite_Holder.GotoXY(1,707,18);

                  Sprite_Holder.GotoXY(2,710,107);

                  break;

               case 2:

                  Group.Sprite_Holder.GotoXY(8,693,22);

                  Group.Sprite_Holder.GotoXY(9,708,156);

                  break;

            }

            Group.Sprite_Holder.SynchronizeTimers();

            Sprite_Holder.SynchronizeTimers();

            Sprite_Holder.EnableTimers();

            Group.Sprite_Holder.EnableTimers();



            Group.Sound_Holder.PlayDSound(0);

            toolbar=0;

            toolbarPhase=0;

         }

         else

         {

            Group.Sprite_Holder.GotoXY(11,-56,-70);

            if(toolbarCase!=11)  Group.Sound_Holder.PlayDSound(2);

            SetCursor(0);

         }

         txtHotSpotOn=0;

         Group.HotSpot_Holder.DisableHotSpot(1);

         Group.HotSpot_Holder.EnableHotSpot(0);

         toolbarCase=0;

         break;

      case 2:

         if(ready==0 && textMode==0)  Sprite_Holder.StopAnimation(0);

         if(txtHotSpotOn==0)   

         {

            Group.Sprite_Holder.GotoXY(11,0,0);

            Group.Sound_Holder.PlayDSound(3);	

         }

         break;

   }

}





void Group.Sprite_Holder.InPlace(int spriteID,int x,int y)

{

   switch(spriteID)

   {

      case 0:

         if(x==480)

         {

            toolbar=1;

            Group.HotSpot_Holder.EnableHotSpot(1);

            SetCursor(1);

         }

         else

         {

            SetCursor(0);

            Group.Sprite_Holder.ChangePhase(2,0);

            Group.Sprite_Holder.ChangePhase(3,0);

            Group.Sprite_Holder.ChangePhase(4,0);

            Group.Sprite_Holder.ChangePhase(5,0);

            Group.Sprite_Holder.ChangePhase(6,0);

            Group.Sprite_Holder.ChangePhase(7,0);

            Group.Sprite_Holder.ChangePhase(8,0);

            Group.Sprite_Holder.ChangePhase(9,0);



            switch(toolbarCase)

            {

               case 2:   //lewo   

                  FadeScreen(0,1000);

                  LoadPage("rycerz.bdf");

                  break;

               case 3:   //prawo

                  FadeScreen(0,1000);

                  LoadPage("slon.bdf");

                  break;

               case 4:   //recytacja

                  FadeScreen(0,1000);

                  LoadPage("rzecz_r.bdf");

                  break;

               case 5:   //roznice

                  FadeScreen(0,1000);

                  LoadPage("rzeczk_c.bdf");

                  break;

               case 6:   //puzzle

                  Group.Sprite_Holder.DisableTimers();

                  Sprite_Holder.DisableTimers();



                  Group.Sprite_Holder.GotoXY(0,480,0);

                  Sprite_Holder.GotoXY(1,547,18);

                  Sprite_Holder.GotoXY(2,550,107);

                  Group.Sprite_Holder.GotoXY(7,557,404);



                  Group.Sprite_Holder.SynchronizeTimers();

                  Sprite_Holder.SynchronizeTimers();

                  Sprite_Holder.EnableTimers();

                  Group.Sprite_Holder.EnableTimers();



                  Group.Sound_Holder.PlayDSound(0);

                  toolbarPhase=1;

                  break;

               case 7:   //Plansza wyboru

                  FadeScreen(0,1000);

                  LoadPage("Wyborw.bdf");

                  break;

               case 8:   //puzzle trudne

                  FadeScreen(0,1000);

                  switch(puzzleNo)

                  {

                     case 1:

                        LoadPage("rzecz1p1.bdf");

                        break;

                     case 2:

                        LoadPage("rzecz2p1.bdf");

                        break;

                 }

                  break;

               case 9:   //puzzle latwe

                  FadeScreen(0,1000);

                  switch(puzzleNo)

                  {

                     case 1:

                        LoadPage("rzecz1p2.bdf");

                        break;

                     case 2:

                        LoadPage("rzecz2p2.bdf");

                        break;

                  }

                  break;

               case 12:

               case 13:

               case 14:

               case 15:

               case 16:

                  Sprite_Holder.ChangePhase(1,0);

                  Sprite_Holder.ChangePhase(2,0);



                  Group.Sprite_Holder.DisableTimers();



                  Group.Sprite_Holder.GotoXY(0,480,0);



                  Group.Sprite_Holder.GotoXY(8,533,22);

                  Group.Sprite_Holder.GotoXY(9,548,156);

                  Group.Sprite_Holder.GotoXY(7,557,404);



                  Group.Sprite_Holder.SynchronizeTimers();

                  Group.Sprite_Holder.EnableTimers();

                  Group.Sound_Holder.PlayDSound(0);

                  toolbarPhase=2;

                  break;

               default:

                  break;

            }

         }

         break;

      case 11:

         if(x==0)

         {

            Group.HotSpot_Holder.EnableHotSpot(1);

            txtHotSpotOn=1;

            SetCursor(1);

         }

         break;

   }

}



void Group.Sprite_Holder.MouseMoveIn(int spriteID)

{

   if(spriteID && toolbar)

      SetCursor(1);

}



void Group.Sprite_Holder.MouseMoveOut(int spriteID)

{

   if(spriteID)

      SetCursor(0);

}



void Group.Sprite_Holder.MouseClickOnDown(int spriteID)

{

   if(spriteID==0)   return;

   if(spriteID==11)

   {

      Group.Sprite_Holder.GotoXY(11,-56,-70);

      Group.Sound_Holder.PlayDSound(2);	

      toolbarCase=spriteID;

      SetCursor(0);

      if(textMode)    textMode=0;

      else            textMode=1;

      SetTextMode();

   }

   else

   {

      Group.HotSpot_Holder.DisableHotSpot(1);

      Group.Sprite_Holder.ChangePhase(spriteID,1);

      switch(spriteID)	

      {

         case 2:   //lewo

         case 3:   //prawo 

            Group.Sound_Holder.PlayDSound(4);

            break;

         case 4:   //recytacja

            Group.Sound_Holder.PlayDSound(5);

            break;

         case 5:   //roznice

            Group.Sound_Holder.PlayDSound(6);

            break;

         case 6:   //puzzle

            Group.Sound_Holder.PlayDSound(7);

            break;

         case 7:   //plansza glowna

            Group.Sound_Holder.PlayDSound(8);

            break;

         case 8:   //puzzle latwe

            Group.Sound_Holder.PlayDSound(9);

            break;

         case 9:   //puzzle trudne

            Group.Sound_Holder.PlayDSound(10);

            break;

         case 10:  //parent window

            Group.Sound_Holder.PlayDSound(4);

            break;

      }

   }

}



void Group.Sprite_Holder.MouseClickOnUp(int spriteID)

{

   if(spriteID==0 || spriteID==5 || spriteID==6 || spriteID==8 || spriteID==9 || spriteID==11)   return;

   Group.Sprite_Holder.DisableTimers();

   Sprite_Holder.DisableTimers();



   Group.Sprite_Holder.GotoXY(0,640,0);

   Group.Sprite_Holder.GotoXY(7,717,404);



   switch(toolbarPhase)

   {

      case 0:

         Group.Sprite_Holder.GotoXY(2,704,14);

         Group.Sprite_Holder.GotoXY(3,744,14);

         Group.Sprite_Holder.GotoXY(4,675,84);

         Group.Sprite_Holder.GotoXY(5,719,210);

         Group.Sprite_Holder.GotoXY(6,718,282);

         break;

      case 1:

         Sprite_Holder.GotoXY(1,707,18);

         Sprite_Holder.GotoXY(2,710,107);

         break;

      case 2:

         Group.Sprite_Holder.GotoXY(8,693,22);

         Group.Sprite_Holder.GotoXY(9,708,156);

         toolbarPhase=0;

         break;

   }

   Group.Sprite_Holder.SynchronizeTimers();

   Sprite_Holder.SynchronizeTimers();

   Sprite_Holder.EnableTimers();

   Group.Sprite_Holder.EnableTimers();



   Group.Sound_Holder.PlayDSound(0);

   toolbar=0;

   Group.HotSpot_Holder.DisableHotSpot(1);

   toolbarCase=spriteID;

}



void Group.Sprite_Holder.EndAnimation(int spriteID)

{

   if(spriteID!=5 && spriteID!=6 && spriteID!=8 && spriteID!=9)   return;



   Group.Sprite_Holder.ChangePhase(spriteID,2);



   Group.Sprite_Holder.DisableTimers();



   if(toolbarPhase==0)

   {

      Group.Sprite_Holder.GotoXY(0,640,0);

      Group.Sprite_Holder.GotoXY(2,704,14);

      Group.Sprite_Holder.GotoXY(3,744,14);

      Group.Sprite_Holder.GotoXY(4,675,84);

      Group.Sprite_Holder.GotoXY(5,719,210);

      Group.Sprite_Holder.GotoXY(6,718,282);

      Group.Sprite_Holder.GotoXY(7,717,404);

   }

   else

   {

      Group.Sprite_Holder.GotoXY(0,640,0);

      Group.Sprite_Holder.GotoXY(8,693,22);

      Group.Sprite_Holder.GotoXY(9,708,156);

      Group.Sprite_Holder.GotoXY(7,717,404);

      toolbarPhase=0;

   }

   Group.Sprite_Holder.SynchronizeTimers();

   Group.Sprite_Holder.EnableTimers();

   Group.Sound_Holder.PlayDSound(0);

   toolbar=0;

   Group.HotSpot_Holder.DisableHotSpot(1);

   toolbarCase=spriteID;

}

